sp_widget.client_script:
api.controller = function($scope, $timeout, $http, $location, $rootScope, amb, spModal, spUtil, $sce, $interpolate, htmlToStringService, $log, i18n, dtechTaskService, dtechOrganizationalUser) {
    //------------------------------------------------------------------------------------------------------------------------
    // COMPANY: DISCOVER TECHNOLOGIES
    // CUSTOMIZED BY: KARINA TORRES
    // RECURSIVE GRAPHICAL TREE FOR PROCESS INSTANCE
    // HELPUL LINKS: https://gojs.net/latest/intro/textblocks.html
    //------------------------------------------------------------------------------------------------------------------------
    // 2.5.21 | 09.08.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
    // 2.7.0 | 2021-06-25 | mmcc | STRY0102408 "Task Tree Manager" tool tip displays "Unicode Decimal Codes" when entering 
    //											some special characters in "instruction" or "Signature Instructions" field
    // 											Add a private function to convert HTML to a simple string
    //											Added missing semicolons, formatted code
    // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering 
    //											some special characters in "instruction" or "Signature Instructions" field
    // 											Remove private function to convert HTML to a simple string; use service instead
    //											Instructions and Signature Instructions need HTML converted to string before
    //											the call to substring with field.maxChars
    //------------------------------------------------------------------------------------------------------------------------
    var c = this;
		var CONST_USER_PREFERENCE_TASK_TREE_PINNED_NAME = 'dtech_task_tree_state_legend_pinned';

    var twjs = x_153465_discovert.twJS;
		var gojsRoundedRectangles = x_153465_discovert.gojsRoundedRectangles;
    var TREE_CONST;
    var modalObjects;
    var $go; // for conciseness in defining templates
    //  UI/UX - STRY0065140 - 2.5 Template List - FIX
    var diagram;
    // this is used to set the initial select percent
    var diagramInitCompleted = false;

    // overview is the picture-in-picture image of the diagram
    var myOverview;
    var treeOrientation;
    var treeOrientationWithinBorder;
    var treeNodeAngle;
    var url_id;
    var watcher;
    // TREE FOOTER TOOLBAR
    var viewPortHeight = 0;
    // call main function
		$scope.activeUnderDraftMessageMaxWidth = "800px";

    main();

    function main() {
				_initializeObjects();
				_loadLegendStates();

        // every time the form is loaded, set not collpased based on whether the accordion is being used
      	// DFCT0012174 - modified from isNotCollapsed to isCollapsed to simplify logic
        c.data.isCollapsed = !c.data.hide_accordion;
        TREE_CONST = _loadTreeConstants();
				_bifoldAdjust();
        $go = go.GraphObject.make; // for conciseness in defining templates

        if (!c.data.selectedId || c.data.selectedId == 'null')
            c.data.selectedId = $location.search().sys_id;
        $scope.page = {
            displayValue: $scope.data.title,
            value: $scope.data.topParentTask_id,
            name: 'page'
        };

        // DFCT0010652 - STRY0119599
        if (c.data.hide_accordion) {
            if (c.data.widgetTreeHeaderToolbars) {
                // load orientation from the header widget
                treeOrientation = c.data.widgetTreeHeaderToolbars[0].data.settings.treeOrientation;
            }
            // DFCT0010674
            resetDiagram();
            // DFCT0011129
            initRecordWatcher($scope.data.table, "u_task_tree=" + $scope.data.task_tree);
        }
    }

		// this seems to only happen on Task, look into more later
		function _bifoldAdjust(){
			// bifold has smaller header.  If not bifold, increase offsets
			if(c.data.isBifold!=true){
				// Adjust top offset to accoutn for Margin and height difference
/*
				var fullScreenOffsetModifier = 9;
				TREE_CONST.topCircleSpanOffset = TREE_CONST.topCircleSpanOffset + fullScreenOffsetModifier;
				TREE_CONST.topIconPanelOffset = TREE_CONST.topIconPanelOffset + fullScreenOffsetModifier;
				TREE_CONST.topOrderOffset = TREE_CONST.topOrderOffset + fullScreenOffsetModifier;
				TREE_CONST.topWarningIconOffset = TREE_CONST.topWarningIconOffset + fullScreenOffsetModifier;
*/
			}
		}

		function _initializeObjects(){
			c.data.iconsInitialized = true;
			c.data.assignmentObject = {};	
			c.data.assignmentObject.objectType = "task";
			c.data.durationObject = {};	
			c.data.durationObject.objectType = "task";
			c.data.operationalObject = {};	
			c.data.operationalObject.objectType = "task";
			//c.data.actions = {};	
			//c.data.actions.objectType = "task";
			c.data.warningObject = {};	
			c.data.warningObject.objectType = "task";
			c.data.orderObject = {};
			c.data.orderObject.objectType = "task";
			c.data.addSubObject = {};
			c.data.addSubObject.objectType = "task";
			c.data.membersObject = {};
			c.data.membersObject.objectType = "task";
		}

		function _loadLegendStates(){
			var legendStates = [];
			legendStates.push({'value':'Draft', 'label': i18n.getMessage('Draft')}); 
			legendStates.push({'value':'Waiting', 'label': i18n.getMessage('Waiting')}); 
			legendStates.push({'value':'Unassigned', 'label': i18n.getMessage('Unassigned')}); 
			legendStates.push({'value':'Assigned', 'label': i18n.getMessage('Assigned')}); 
			legendStates.push({'value':'Accepted', 'label': i18n.getMessage('Accepted')}); 
			legendStates.push({'value':'Rejected', 'label': i18n.getMessage('Rejected')}); 
			legendStates.push({'value':'Work in Progress', 'label': i18n.getMessage('Work in Progress')}); 
			legendStates.push({'value':'In Review', 'label': i18n.getMessage('In Review')}); 
			legendStates.push({'value':'Rework', 'label': i18n.getMessage('Rework')}); 
			legendStates.push({'value':'Completed', 'label': i18n.getMessage('Completed')}); 
			c.data.legendStates = legendStates;
			c.data.hideLegend = c.data.preferences[CONST_USER_PREFERENCE_TASK_TREE_PINNED_NAME].value != true;
		}

		$scope.loadActions = function(taskSysId){
			// STRY0117600 - does not like diagram posted back to server
			c.data.widgetTreeFooterToolbars[0].diagram = null;
			c.data.widgetTreeHeaderToolbars[0].diagram = null;

			$scope.data.getActions = true;
			$scope.data.taskSysId = taskSysId;
			spUtil.update($scope).then(function(){
				c.data.widgetTreeFooterToolbars[0].diagram = diagram;
				c.data.widgetTreeHeaderToolbars[0].diagram = diagram;
			});
		};	
    // STRY0117600
