            fontStyle: "14px Segoe UI",
            fontStyleTaskerNumber: "12px Segoe UI",
            fontStyleNodeDetails: "10px Segoe UI",
						// tree color change
						// textStrokeColor: "white",
            textStrokeColor: "#000000",
						textStrokeTaskerNumber: "#757575",
						textStrokeNodeDetails: "#757575",
						textStrokeInactive: "#FFFFFF",

            node_id: "page_map",
            minHeight: 435,
            diagramMinHeight: 150,
            horizontalTreeAngle: 0,
            verticalTreeAngle: 90,
						// Expander button and port offsets
						rightTreeExpanderOffset: -15,
						bottomTreeExpanderOffset: -15,
						rightTreePortOffset: 6,
						leftTreePortOffset:-9,
						topTreePortOffset: -9,
						bottomTreePortOffset:6,
						// Boarder, selected node and hover node 
            outlineWidth: 2,
