						orderNormalFill: '#757575', 
						orderHoverFill: '#70087D2', 
						selectedOutlineBorderColor: "#80D1FF",
						selectedOutlineWidth: 7,
						hoverRectangleOffset: 10,
						// Router Order Constants
						leftOrderOffset: -1,
						topOrderOffset: -1,
						orderTextColor: '#FFFFFF',					
						fontStyleOrderCircle: "12px Segoe UI",
						topCircleSpanOffset: 46,
						leftRouteCircleOffset: -5,
						topRouteCircleOffset: -5,
						// warnining Constatns
						warningPanelXoffset: -7,
						warningPanelYoffset: 7,
						topWarningIconOffset: 43,
						leftWarningIconOffset: -1,
						warningIconMargin: 2,
						warningPanelHeight: 26,
						warningPanelWidth: 26,
						warningPanelStrokeWidth: 2, 
						warningPanelStokeColor: "#FFFFFF",
						// status Constatns
						statusPanelHeight: 16,
						statusPanelWidth: 16,
						statusPanelXoffset: 30,
						statusPanelYoffset: -28,
						statusPanelStrokeWidth: 2, 
						statusPanelStokeColor: "#FFFFFF",
						statusIconMargin: 2,

						// Icon Panel constants
						leftIconPanelOffset: -93,
						topIconPanelOffset: 23,
						topCornerOffset: -7, // offset desired is 7 - this should start the image 7 pixels early
						rightCornerOffset: -9, // offset desired is 7, images are 16, starting 9 pixes inside should hang seven off outside			
						iconOutlineWidth: 2,
						iconOutlineColor: '#FFFFFF',
						iconPicSize:16,
						// profile picture constants
						profilePicOffset: 8,
						profilePicSize: 24,
						profilePicCircleSize: 26,
						profilePicBorder: '#FFFFFF',
						profilePicTextStroke: '#FFFFFF',
						profilePicFill: '#787878',
						memberPanelTopOffset: 15,
						memberPanelLeftOffset:-3,

						topPicCornerOffset: 17,
						leftPicCornerOffset: 17,
						fontStyleProfileInitials: "bold 12px Segoe UI",

						// tree color change
						// node_active_bg: '#33738e',
            node_active_bg: '#FFFFFF',					
            node_inactive_bg: '#787878',
						// tree color change
						node_border: '#757575',
            node_selected_border: "#00A4FF", //'#ADD8E6',
            node_selected_border_stroke_width: 4,

            nodeOuterRectangelWidth: 310,
            nodeOuterRectangelHeight: 70,
						taskStateIndicatorWidth: 12,
            nodeTextPanelLeftMargin: 30,
						nodeTextPanelRightMargin: 20,
            textPanelMinWidth: 240,
            textPanelMinHeight: 35,
            textPanelMaxWidth: 240,
            textPanelMaxHeight: 55,

            spacingNode: -5,
            spacingLayer: 60,
						iconPanelWidth: 150,					
						iconPanelHeight: 20,
						iconPanelFillColor: '#263341',

            // NOTE: other trees set this default to 700, but task tree is setting to 200
            toolTipHoverDelay: 700,
            toolTipDuration: 10000,
            node_status_ontime: '#37C1C3', //success
            node_status_warning: '#F6C716', //warning
            node_status_critical: '#E32921', //danger

            state_flag_colors: {
                "waiting": {
                    bg: '#6b6b6b',
                    text: 'white',
                    warning: '#F6C716',
                    hover: '#F00'
                },
                "unassigned": {
                    bg: '#F6C716',
                    text: '#434343',
                    warning: '#000000',
                    hover: '#F00'
                },
                "assigned": {
                    bg: '#427A93',
                    text: 'white',
                    warning: '#000000',
                    hover: '#F00'
                },
                "accepted": {
                    bg: '#A0D468',
                    text: '#434343',
                    warning: '#000000',
                    hover: '#2E3C54'
                },
                "rejected": {
                    bg: '#E32921',
                    text: 'white',
                    warning: '#000000',
                    hover: '#F5F5F5'
                },
                "workinprogress": {
                    bg: '#2E3C54',
                    text: 'white',
                    warning: '#F6C716',
                    hover: '#F5F5F5'
                },
                "workscheduled": {
                    bg: '#2E3C54',
                    text: 'white',
                    warning: '#F6C716',
                    hover: '#F5F5F5'
                },
                "inreview": {
                    bg: '#736ac6',
                    text: 'white',
                    warning: '#000000',
                    hover: '#F5F5F5'
                },
                "rework": {
                    bg: '#2E3C54',
                    text: 'white',
                    warning: '#F6C716',
                    hover: '#F5F5F5'
                },
                "completed": {
                    bg: '#37C1C3',
                    text: '#434343',
                    warning: '#000000',
                    hover: '#2E3C54'
                },
                "closedincomplete": {
                    bg: '#37C1C3',
                    text: '#434343',
                    warning: '#000000',
                    hover: '#2E3C54'
                },
                "cancelled": {
                    bg: '#37C1C3',
                    text: '#434343',
                    warning: '#000000',
                    hover: '#2E3C54'
                },
                "colorDefault": {
                    bg: '#6b6b6b',
                    text: 'white',
                    warning: '#F6C716',
                    hover: '#F00'
                }
            },
        };
        return oTREE_CONST;
    }

// RAJ - new tree
    function getStateColorFlag(state) {
        var bg_color;
        switch (state) {
            case "-3": // waiting
                bg_color = TREE_CONST.state_flag_colors.waiting.bg;
                break;
            case "-5": // unassigned
                bg_color = TREE_CONST.state_flag_colors.unassigned.bg;
                break;
            case "1": // assigned
                bg_color = TREE_CONST.state_flag_colors.assigned.bg;
                break;
            case "10": // accepted
                bg_color = TREE_CONST.state_flag_colors.accepted.bg;
                break;
            case "11": // rejected
                bg_color = TREE_CONST.state_flag_colors.rejected.bg;
                break;
            case "13": // workinprogress
                bg_color = TREE_CONST.state_flag_colors.workinprogress.bg;
                break;
            case "12": // workscheduled
                bg_color = TREE_CONST.state_flag_colors.workscheduled.bg;
                break;
            case "14": // inreview
                bg_color = TREE_CONST.state_flag_colors.inreview.bg;
                break;
            case "15": // rework
                bg_color = TREE_CONST.state_flag_colors.rework.bg;
                break;
            case "3": // completed
                bg_color = TREE_CONST.state_flag_colors.completed.bg;
                break;
            case "4": // closedincomplete
                bg_color = TREE_CONST.state_flag_colors.closedincomplete.bg;
                break;
            case "7": // cancelled
                bg_color = TREE_CONST.state_flag_colors.cancelled.bg;
                break;
            default:
                bg_color = TREE_CONST.state_flag_colors.colorDefault.bg;
        }
        return bg_color;
    }

		// this function sets all toolbars to false
		function _clearDirectiveHovers(){
			c.data.showIcons = false;
			c.data.operationalToolTipOpen = false;
			c.data.assignmentToolTipOpen = false;
			c.data.durationToolTipOpen = false;
			c.data.actionToolTipOpen =false;
			c.data.addSubActionToolTipOpen = false;
			c.data.overPanel = false;
			c.data.showWarning=false;
			c.data.overWarningIcon=false;
			c.data.warningToolTipOpen = false;
			c.data.showOrder=false;
			c.data.overOrder=false;
			c.data.orderToolTipOpen=false;
			c.data.showMembers = false;
			c.data.overMember = false;
			c.data.membersToolTipOpen = false;
		}

    // -----------------------------------------------------------------------------------------------------------------
    // START RECORD WATCHER BLOCK
    // -----------------------------------------------------------------------------------------------------------------
    function initRecordWatcher(table, filter) {
        if (watcher)
            watcher.unsubscribe();

        if (table && filter) {
            // STRY0093948 - when a row is removed, broadcast event to Tab Form with Tabs to update the count
            var params = {};
            var watcherChannel = amb.getChannelRW(table, filter);
            amb.connect();
            watcher = watcherChannel.subscribe(function(name) {
								var requiresRedraw = false;
                var changes = name.data.changes;
                var sys_id = name.data.sys_id;
                switch (name.data.operation) {
                    case "update":
                        var nodeChangedFound = diagram.model.findNodeDataForKey(sys_id);
                        if (nodeChangedFound) {
                            var nodeDataChanged = false;
                            for (var change in changes) {
                                if (c.data.fieldsInModel[changes[change]]) {
                                    nodeDataChanged = true;
                                    if (changes[change] == 'order' || changes[change] == 'task_order') {
																			requiresRedraw = true;
																		}
                                    break;
                                }
                            }
                            if (nodeDataChanged) {
                                updateModelNodeData(nodeChangedFound, name.data.record);
                            }
                        }
                        break;
                    case "insert":
                        // 2.7.0 | 2021-11-02 | mmcc | DFCT0010588 - When creating a Subtask on the Task form, record watcher shows 2 subtasks created
                        // .model.findNodeDataForKey() returns null if a node data with that key cannot be found in the model...
                        var isNotFoundNodeInsert = diagram.model.findNodeDataForKey(sys_id) == null;
                        if (isNotFoundNodeInsert) {
                            if (name.data.record.parent) {
                                var newNodeData = createModelNodeData(sys_id, name.data.record);
                                diagram.startTransaction("Add new Task");
                                diagram.model.addNodeData(newNodeData);
                                diagram.model.setParentKeyForNodeData(newNodeData, name.data.record.parent.value);
                                diagram.commitTransaction("Add new Task");
                                // if suspensedate changed, need to check parent and all subtasks again
                                checkDateWarnings(newNodeData);
                            }
                        }
                        break;
                    case "delete":
                        var nodeDataOfDeleted = diagram.model.findNodeDataForKey(sys_id);
                        if (nodeDataOfDeleted) {
                            diagram.model.removeNodeData(nodeDataOfDeleted);
														// 2.8.1 | 2022-12-19 | mmcc | DFCT0011241 - Draft task deleted, info message should NOT display; added if else if
														if (c.data.selectedId == sys_id) {
															c.data.isTopTaskOrNotDraft = true;
															var parentNodeOfNodeDeleted =  diagram.findNodeForKey(nodeDataOfDeleted.parent);

															// when the selected node is the deleted node, try to select it's parent
															if (parentNodeOfNodeDeleted) {
																// make it the selected Node
																diagram.select(parentNodeOfNodeDeleted);
																nodeSelectionChanged(parentNodeOfNodeDeleted);
															}

														} else if(c.data.selectedId != sys_id) {
															var nodeSelectedItem = diagram.findNodeForKey(c.data.selectedId);

															// when the selected node is NOT the deleted node, re-select the selected node
															nodeSelectionChanged(nodeSelectedItem);
														}
                        }
                }
								_clearDirectiveHovers();
								if(requiresRedraw){
									//	drawTree();	
									diagram.layoutDiagram(true);
								}							
            });
        }
    }

    // load all of the field names used in the task tree nodes (see TaskHelpers.getTaskTreeLevelO and TaskHelpers.getTaskTitleNode)
    function createModelNodeData(sys_id, record) {
        var newNodeData = {};
        newNodeData.key = sys_id;
        newNodeData.sys_id = sys_id;
        for (var key in record) {
            var displayValue = '';
            var fieldLabel = '';
            var field = c.data.fieldsInModel[key];
            if (field) {
                fieldLabel = field.fieldLabel;

                // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode
                // displayValue = record[key].display_value;
                if ((field.fieldName == 'u_signature_instructions') || (field.fieldName == 'instructions')) {
                    displayValue = htmlToStringService.convertHtmlToString(record[key].display_value);
                } else {
                    displayValue = record[key].display_value;
                }

                if (field.maxChars > 0)
                    displayValue = displayValue.toString().length > field.maxChars ? displayValue.substring(0, field.maxChars - 1) : displayValue.toString();
                if (field.hasValue) {
                    // many have value, only a few have only value 'calchaschildren', 'parent', 'u_wait_for_subtasks_to_finish'
                    // others 'primary_assignee', 'primary_office', 'tasking_authority', 'state', 'assigned_to'
                    newNodeData[key] = record[key].value;
                }
                if (field.keyUsesDisplayOnly) {
                    // 'status', 'task_name', 'u_active_subtasks', 'order', 'u_reviewer': 
                    newNodeData[key] = displayValue;
                }
                if (field.hasDiplayValue) {
                    // 'state_DisplayValue', 'assigned_to_DisplayValue'
                    newNodeData[key + '_DisplayValue'] = displayValue;
                }
                if (field.type == 'date') {
                    // DFCT0011140  - get date in user's timezone
                    var date_number = getDateFromFormat(record[key].display_value, g_user_date_time_format);
                    var tzDate = new Date();
                    var tzMinOffset = tzDate.getTimezoneOffset();
                    var tzOffset = tzMinOffset * 60 * 1000;
                    date_number = date_number - tzOffset;
                    newNodeData[key] = date_number;
                }
                //  STRY0113883
                if (field.type == 'photo' || field.type == 'profile') {
                    // these are handled in a function b/c they need to post back to the server
                    loadUserInfo(field.type, newNodeData.key, key, record[key].value, displayValue );
                }							
            } //if field wasn't found do nothing
        }


        // DFCT0011078
        newNodeData.name = getTaskTitleNode(newNodeData);
        newNodeData.nodeDetails = getTaskNodeDetails(newNodeData);

        newNodeData.warning = {};

        // DFCT0010684 - This code needs to mirror the code in uiConditionCheck for canCreateSubTask
        newNodeData.canCreateSubTask = ((newNodeData.state != 3 && newNodeData.state != 4 && newNodeData.state != 7) &&
            (c.data.currentUser == newNodeData.assigned_to || c.data.currentUser == newNodeData.u_task_requester));

        // STRY0095748 - no suspensedate warning
        newNodeData.warning.noSuspenseDate = (newNodeData.suspense_date == '' || newNodeData.suspense_date == null);
        // New cannot be top in this context.  So, set to false on exteneral inbound fo task
        newNodeData.isInboundExternalOU = false;
        newNodeData.warning.isTopSuspenseDateAfterExternalInboundDate = false;
        newNodeData.isOutboundExternalOU = (record.outbound == true);
        newNodeData.warning.isTopSuspenseDateBeforeExternalOutboundDate = newNodeData.isOutboundExternalOU && (record.u_external_due_date > record.suspense_date);

        newNodeData.warning.waitStatewithNoSubtasks = (((newNodeData.u_wait_for_subtasks_to_finish == 'true') &&
                (parseInt(newNodeData.calchaschildren) == 0)) ||
            (((newNodeData.u_wait_for_subtasks_to_finish == 'true') &&
                (parseInt(newNodeData.calchaschildren) != 0) &&
                (newNodeData.state == -3) &&
                (parseInt(newNodeData.u_active_subtasks) == 0)
            )));

				// DFCT0012129 - if waiting, but not for subtasks, then add the previous order message
				if(!newNodeData.warning.waitStatewithNoSubtasks && newNodeData.state==-3){
					newNodeData.warning.waitStateOrderBy = true;
				}

        newNodeData.warning.primaryAssigneeEmpty = (newNodeData.primary_assignee == '' || newNodeData.primary_assignee == null);
        newNodeData.warning.assignedMemberEmpty = ((newNodeData.assigned_to == '' || newNodeData.assigned_to == null));

        // if status is not provided on a new record, set to unkown
        if (!newNodeData.status)
            newNodeData.status = 'unkown';

        return newNodeData;
    }

    // load all of the field names used in the task tree nodes (see TaskHelpers.getTaskTreeLevelO and TaskHelpers.getTaskTitleNode)
    function updateModelNodeData(nodeData, record) {
        for (var key in record) {
            var displayValue = '';
            var fieldLabel = '';
            var field = c.data.fieldsInModel[key];
            if (field) {
                fieldLabel = field.fieldLabel;

                // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode
                // displayValue = record[key].display_value;
                if ((field.fieldName == 'u_signature_instructions') || (field.fieldName == 'instructions')) {
                    displayValue = htmlToStringService.convertHtmlToString(record[key].display_value);
                } else {
                    displayValue = record[key].display_value;
                }

                if (field.maxChars > 0)
                    displayValue = displayValue.toString().length > field.maxChars ? displayValue.substring(0, field.maxChars - 1) : displayValue.toString();
                if (field.hasValue) {
                    // many have value, only a few have only value 'calchaschildren', 'parent', 'u_wait_for_subtasks_to_finish'
                    // others 'primary_assignee', 'primary_office', 'tasking_authority', 'state', 'assigned_to'
                    diagram.model.setDataProperty(nodeData, key, record[key].value); // this is the default value to key match
                }
                if (field.keyUsesDisplayOnly) {
                    // 'status', 'task_name', 'u_active_subtasks', 'order', 'u_reviewer': 
                    diagram.model.setDataProperty(nodeData, key, displayValue);
                }
                if (field.hasDiplayValue) {
                    // 'state_DisplayValue', 'assigned_to_DisplayValue'
                    diagram.model.setDataProperty(nodeData, key + '_DisplayValue', displayValue);
                }
                if (field.type == 'date') {
                    // DFCT0011140  - get date in user's timezone
                    var date_number = getDateFromFormat(record[key].display_value, g_user_date_time_format);
                    var tzDate = new Date();
                    var tzMinOffset = tzDate.getTimezoneOffset();
                    var tzOffset = tzMinOffset * 60 * 1000;
                    date_number = date_number - tzOffset;
                    diagram.model.setDataProperty(nodeData, key, date_number);
                }
                if (field.type == 'photo'  || field.type == 'profile') {
                    // these are handled in a function b/c they need to post back to the server
                    loadUserInfo(field.type, nodeData.key, key, record[key].value, displayValue );
                }							
            } //if field wasn't found do nothing
        }
        var nameValue = getTaskTitleNode(nodeData);
        if (nodeData.name != nameValue) {
            diagram.model.setDataProperty(nodeData, 'name', nameValue);
        }

        // DFCT0011078
        var nodeDetails = getTaskNodeDetails(nodeData);
        if (nodeData.nodeDetails != nodeDetails) {
            diagram.model.setDataProperty(nodeData, 'nodeDetails', nodeDetails);
        }

        // DFCT0010684 - This code needs to mirror the code in uiConditionCheck for canCreateSubTask
        var canCreateSubTask = ((nodeData.state != 3 && nodeData.state != 4 && nodeData.state != 7) &&
            (c.data.currentUser == nodeData.assigned_to || c.data.currentUser == nodeData.u_task_requester));
        if (nodeData.canCreateSubTask != canCreateSubTask) {
            diagram.model.setDataProperty(nodeData, 'canCreateSubTask', canCreateSubTask);
        }

        var newWaitStateWithNoSubtasks = (((nodeData.u_wait_for_subtasks_to_finish == 'true') &&
                (parseInt(nodeData.calchaschildren) == 0)) ||
            (((nodeData.u_wait_for_subtasks_to_finish == 'true') &&
                (parseInt(nodeData.calchaschildren) != 0) &&
                (nodeData.state == -3) &&
                (parseInt(nodeData.u_active_subtasks) == 0)
            )));
        if (nodeData.warning.waitStatewithNoSubtasks != newWaitStateWithNoSubtasks) {
            diagram.model.setDataProperty(nodeData.warning, 'waitStatewithNoSubtasks', newWaitStateWithNoSubtasks);
        }
				// DFCT0012129 - if waiting, but not for subtasks, then add the previous order message
				var newWaitStateOrderBy = false;
				if(!newWaitStateWithNoSubtasks && nodeData.state==-3){
					newWaitStateOrderBy = true;
				}
        if (nodeData.warning.waitStateOrderBy != newWaitStateOrderBy) {
            diagram.model.setDataProperty(nodeData.warning, 'waitStateOrderBy', newWaitStateOrderBy);
        }

        // STRY0095748 - no suspensedate warning
        var newSuspenseDateFlag = (nodeData.suspense_date == '' || nodeData.suspense_date == null);
        if (nodeData.warning.noSuspenseDate != newSuspenseDateFlag) {
            diagram.model.setDataProperty(nodeData.warning, 'noSuspenseDate', newSuspenseDateFlag);
        }
        var newExtInboundFlag = nodeData.isInboundExternalOU && (nodeData.suspense_date > nodeData.u_external_due_date);
        if (nodeData.warning.isTopSuspenseDateAfterExternalInboundDate != newExtInboundFlag) {
            diagram.model.setDataProperty(nodeData.warning, 'isTopSuspenseDateAfterExternalInboundDate', newExtInboundFlag);
        }
        var newExtOutboundFlag = nodeData.isOutboundExternalOU && (nodeData.u_external_due_date > nodeData.suspense_date);
        if (nodeData.warning.isTopSuspenseDateBeforeExternalOutboundDate != newExtOutboundFlag) {
            diagram.model.setDataProperty(nodeData.warning, 'isTopSuspenseDateBeforeExternalOutboundDate', newExtOutboundFlag);
        }

        var primaryAssigneeEmpty = (nodeData.primary_assignee == '' || nodeData.primary_assignee == null);
        if (primaryAssigneeEmpty != nodeData.warning.primaryAssigneeEmpty) {
            diagram.model.setDataProperty(nodeData.warning, 'primaryAssigneeEmpty', primaryAssigneeEmpty);
        }
        var assignedMemberEmpty = ((nodeData.assigned_to == '' || nodeData.assigned_to == null));
        if (assignedMemberEmpty != nodeData.warning.assignedMemberEmpty) {
            diagram.model.setDataProperty(nodeData.warning, 'assignedMemberEmpty', assignedMemberEmpty);
        }
        // if suspensedate changed, need to check parent and all subtasks again
        checkDateWarnings(nodeData);
        diagram.model.updateTargetBindings(nodeData);
    }

		// STRY0113883 load user profile and/or Photo information
		function loadUserInfo(fieldType, nodeKey, fieldName, value, displayValue){
			c.data.getUserGUID = value;

			if (fieldType == 'photo' ||
					fieldType == 'profile') {
				dtechOrganizationalUser.getUserProfile(value).then(function(response){
					var userProfile = response.userProfile;
					updateProfileData(nodeKey, fieldName, userProfile.name, userProfile.photo, userProfile);
				});
			}
		}

		function updateProfileData(nodeKey, fieldName, name, photo, updatedProfile){
			// find the node to update again
			var nodeData = diagram.model.findNodeDataForKey(nodeKey);
			if (nodeData) {
				nodeData[fieldName + '_photoName'] = name;
				diagram.model.setDataProperty(nodeData, fieldName + '_photoName', name);

				if(photo){
					nodeData[fieldName + '_photo'] = photo;
					diagram.model.setDataProperty(nodeData, fieldName + '_photo', photo);
				}

				if(updatedProfile){
					nodeData[fieldName + '_profile'] = updatedProfile;
					diagram.model.setDataProperty(nodeData, fieldName + '_profile', updatedProfile);
				}
				diagram.model.updateTargetBindings(nodeData);
			}
		}

    function getTaskTitleNode(nodeData) {
        var nodeTitle = nodeData.short_description;
        return nodeTitle;
    }

    function getTaskNodeDetails(nodeData) {
        // DFCT0011078
        var nodeDetails = "";
        var active_subtasks = 0;
        if (nodeData.u_active_subtasks != null && nodeData.u_active_subtasks != "null" &&
            nodeData.u_active_subtasks != undefined && nodeData.u_active_subtasks != "undefined") {
            active_subtasks = nodeData.u_active_subtasks;
        }

        switch (nodeData.state_DisplayValue) {
            case 'Waiting':
                if (nodeData.calchaschildren == '0')
                    nodeDetails += nodeData.state_DisplayValue + " on creating Subtasks ";
                else
                    nodeDetails += nodeData.state_DisplayValue + " on " + active_subtasks + " out of " + nodeData.calchaschildren + " Subtasks";
                break;
            case 'Assigned':
                nodeDetails += nodeData.state_DisplayValue + " to " + nodeData.assigned_to_DisplayValue;
                break;
                // DFCT0011179
            case 'Accepted':
            case 'Work in Progress':
            case 'Completed':
                // STRY0128732 Task Tree- Improved Messaging for Decision Made on Approval and Concurrence Tasker Types
                if (nodeData.decision_DisplayValue && nodeData.decision_DisplayValue != "" && nodeData.decision_DisplayValue != 'N/A') {
                    nodeDetails += nodeData.decision_DisplayValue + " by " + nodeData.assigned_to_DisplayValue;
                } else {
                    nodeDetails += nodeData.state_DisplayValue + " by " + nodeData.assigned_to_DisplayValue;
                }
                break;
            case 'In Review':
                nodeDetails += nodeData.state_DisplayValue + " by " + nodeData.u_reviewer + ", Worked by " + nodeData.assigned_to_DisplayValue;
                break;
            default:
                nodeDetails += nodeData.state_DisplayValue;
                break;
        }
        return nodeDetails;
    }

    function checkDateWarnings(changedNodeData) {
        if (changedNodeData.parent != '' && changedNodeData.parent != undefined) {
            var parentNodeData = diagram.model.findNodeDataForKey(changedNodeData.parent);
            compareParentDateToAllChildren(parentNodeData.sys_id);
        }
        compareParentDateToAllChildren(changedNodeData.sys_id);
    }

    function compareParentDateToAllChildren(parentKey) {
        var parentNode = diagram.findNodeForKey(parentKey);
        var childrenNodes = parentNode.findTreeChildrenNodes();
        var parentAfterAllChildren = true;
        while (childrenNodes.next()) {
            var node = childrenNodes.value;
            var childAfterParent = (node.data.suspense_date > parentNode.data.suspense_date);
            if (childAfterParent) {
                parentAfterAllChildren = false;
            }
            diagram.model.setDataProperty(node.data.warning, 'isSuspenseDateAfterParent', childAfterParent);
            diagram.model.updateTargetBindings(node.data);
        }
        diagram.model.setDataProperty(parentNode.data.warning, 'isSuspenseDateAfterChildren', parentAfterAllChildren);
        diagram.model.updateTargetBindings(parentNode.data);
    }
