    // **************************************************************************************************************	
    // DRAW TREE AND TREE LAYOUT FUCNTIONS
    // This block contains the functions that define the tree structure and capabilities
    // START BLOCK
    // **************************************************************************************************************	
		function _createHoverRoundedRectangle(){
			var hoverRoundedRectangle = 
					$go(go.Shape, "RoundedRectangle",
							{name: "hoverRoundedRectangle", 
							 portId: "",  // now the Shape is the port, not the whole Node
							 strokeWidth:TREE_CONST.selectedOutlineWidth,
							 stroke: TREE_CONST.selectedOutlineBorderColor,
							 width: TREE_CONST.nodeOuterRectangelWidth + TREE_CONST.hoverRectangleOffset,
							 height: TREE_CONST.nodeOuterRectangelHeight + TREE_CONST.hoverRectangleOffset,
							 parameter1:10
							},

							new go.Binding("toSpot", "", function()
														 {var newToSpot;
															if(treeOrientation == "Horizontal"){
																newToSpot = new go.Spot(0,0.5, TREE_CONST.leftTreePortOffset, 0);
															} else if(treeOrientation == "Vertical"){
																newToSpot = new go.Spot(0.5,0, 0, TREE_CONST.topTreePortOffset);
															}
															return newToSpot;
														 }),
							new go.Binding("fromSpot", "", function()
														 {var newfromSpot;
															if(treeOrientation == "Horizontal"){
																newfromSpot = new go.Spot(1,0.5, TREE_CONST.rightTreePortOffset, 0);
															} else if(treeOrientation == "Vertical"){
																newfromSpot = new go.Spot(0.5,1, 0, TREE_CONST.bottomTreePortOffset);
															}
															return newfromSpot;
														 }),
							new go.Binding("stroke", "isSelected", function(s) 
														 {if (s)
															 return TREE_CONST.selectedOutlineBorderColor;
															else
																return "#FFFFFF";
														 }).ofObject(""),
							new go.Binding("fill", "isSelected", function(s) 
														 {if (s)
															 return TREE_CONST.selectedOutlineBorderColor;
															else
																return "#FFFFFF";
														 }).ofObject("")
						 );
			return hoverRoundedRectangle;
		}	

