		function _membersShowHide(memberPic, show){
			var memberPanelPosition;
			var memberDiv;
			var nodeObject;
			var docLoc;
			$scope.data.item_id = memberPic.part.data.key;
			// clear member object if not same id
			if(!$scope.data.membersObject || $scope.data.membersObject.taskId != $scope.data.item_id){
				c.data.membersObject = {};
				c.data.membersObject.objectType = "task";
			}

			c.data.showMembers=show;
			if(show){
				nodeObject = diagram.findNodeForKey($scope.data.item_id);
				var outerRoundedRectangle = nodeObject.findObject('OuterRoundedRectangle');

				memberPanelPosition = outerRoundedRectangle.getDocumentPoint(go.Spot.Left);
				docLoc = diagram.transformDocToView(memberPanelPosition);
				memberDiv = angular.element(document.getElementById('memberPanel'))[0];

				memberDiv.style.left = Math.ceil(docLoc.x + TREE_CONST.memberPanelLeftOffset) + 'px';
				memberDiv.style.top = Math.ceil(docLoc.y + TREE_CONST.memberPanelTopOffset) + 'px';				
			}
			$timeout(function() {
				$scope.$apply();
			});	
		}

		function _getMaxRouteOrder(orderPanel){
			var nodePanel = orderPanel.part;
				var nodeParent = nodePanel.findTreeParentNode();
			var itSiblings = nodeParent.findTreeChildrenNodes();
			var maxOrder = 0;
			while (itSiblings.next()) {
				var sibling = itSiblings.value;
// TODO - check this against route order in directive for task vs template
				var curOrder = parseInt(sibling.data.order);
				if( curOrder > maxOrder){
					maxOrder = curOrder;
				}
			}
			return maxOrder;
		}

		function _orderCircleShowHide(orderPanel, show){
			var orderPanelPosition;
			var orderCircleSpan;
			var docLoc;
			$scope.data.item_id = orderPanel.part.data.key;
// TODO - check this against route order in directive for task vs template			
			// get max order
			c.data.orderObject.max_route_order = {};
			c.data.orderObject.max_route_order.value = _getMaxRouteOrder(orderPanel);
			c.data.orderObject.route_order = {};
// changed, this, but not above, check directive
			c.data.orderObject.route_order.value = parseInt(orderPanel.part.data.order);
			c.data.showOrder=show;
			if(show){
				orderPanelPosition = orderPanel.getDocumentPoint(go.Spot.Left);
				docLoc = diagram.transformDocToView(orderPanelPosition);
				orderCircleSpan = angular.element(document.getElementById('orderCircle'))[0];
				orderCircleSpan.style.left = Math.ceil(docLoc.x + TREE_CONST.leftRouteCircleOffset) + 'px';
				orderCircleSpan.style.top = Math.ceil(docLoc.y + TREE_CONST.topCircleSpanOffset) + 'px';
			}
			$timeout(function() {
				$scope.$apply();
			});	
		}

    // common styling for each indicator
    function _createOrderCircle() { // the data property name
			var orderCircle = 
					$go(go.Shape, "Circle",
							{width: 16,
							 height: 16,
							 fill: TREE_CONST.orderNormalFill,
							 margin: 5
							},
							new go.Binding("alignment", "", function()
														 {var newAlignment;
															if(treeOrientation == "Horizontal"){
																newAlignment = new go.Spot(0,0.5, TREE_CONST.leftOrderOffset, 0);
															} else if(treeOrientation == "Vertical"){
																newAlignment = new go.Spot(0.5,0, 0, TREE_CONST.topOrderOffset);
															}
															return newAlignment;
														 }),
							new go.Binding("visible", "", function (data)
														 {if(data.parent){
															 return true;
														 } else {
															 return false;
														 }})
						 );
			return orderCircle;
		}

		function _createOrderPanel(){
			var orderPanel = 
					$go(go.Panel, "Spot",  // panel for Order
							new go.Binding("alignment", "", function()
														 {var newAlignment;
															if(treeOrientation == "Horizontal"){
																newAlignment = new go.Spot(0,0.5, TREE_CONST.leftOrderOffset, 0);
															} else if(treeOrientation == "Vertical"){
																newAlignment = new go.Spot(0.5,0, 0, TREE_CONST.topOrderOffset);
															}
															return newAlignment;
														 }),
							new go.Binding("visible", "", function (data)
														 {if(data.parent){
															 return true;
														 } else {
															 return false;
														 }}),
							{mouseEnter: function(e, obj) 
							 {_orderCircleShowHide(obj, true);},
							 mouseLeave: function(e, obj)
							 {_orderCircleShowHide(obj, false);}
							},
							$go(go.TextBlock,
									{alignment: go.Spot.Center,
									 stroke: TREE_CONST.orderTextColor,
									 font: TREE_CONST.fontStyleOrderCircle
									},
									new go.Binding("text", "", function(data) 
																 {return data.order;}
																)
								 )
						 );
			return orderPanel;
		}

		function _iconPanelShowHide(nodeObject, show){
			var iconPanelPosition;
			var iconSpan;
			var docLoc;
			var outerRoundedRectangle = nodeObject.findObject('OuterRoundedRectangle');

			$scope.data.item_id = nodeObject.part.data.key;
			c.data.addSubObject.title =	c.data.messages["Tasker - Add a Subtask"] + ': ' + nodeObject.part.data.name;
			c.data.showIcons=show;
			if(show){
				outerRoundedRectangle.stroke=TREE_CONST.node_selected_border;

				iconPanelPosition = outerRoundedRectangle.getDocumentPoint(go.Spot.TopCenter);
				docLoc = diagram.transformDocToView(iconPanelPosition);
				iconSpan = angular.element(document.getElementById('iconSpan'))[0];
				iconSpan.style.left = Math.ceil(docLoc.x + TREE_CONST.leftIconPanelOffset) + 'px';
				iconSpan.style.top = Math.ceil(docLoc.y + TREE_CONST.topIconPanelOffset) + 'px';				
			} else {
				outerRoundedRectangle.stroke=_setNodeOutline(nodeObject.part.data.status);
			}
			$timeout(function() {
				$scope.$apply();
			});
		}	

		function _setNodeOutline(status){
			switch (status) {
				case "Projected on time":
					return TREE_CONST.node_border;
				case "Warning":
					return TREE_CONST.node_status_warning;
				case "Critical":
					return TREE_CONST.node_status_critical;
				default:
					return TREE_CONST.node_border;
			}

		}

		function _warningiconShowHide(warningPic, show){
			var warningPanelPosition;
			var iconSpan;
			var docLoc;
			$scope.data.item_id = warningPic.part.data.key;
			c.data.showWarning=show;
			if(show){
				warningPanelPosition = warningPic.getDocumentPoint(go.Spot.Left);
				docLoc = diagram.transformDocToView(warningPanelPosition);
				iconSpan = angular.element(document.getElementById('warningIcon'))[0];
				iconSpan.style.left = Math.ceil(docLoc.x + TREE_CONST.leftWarningIconOffset) + 'px';
				iconSpan.style.top = Math.ceil(docLoc.y + TREE_CONST.topWarningIconOffset) + 'px';				
			}
			$timeout(function() {
				$scope.$apply();
			});	
		}


		function _createStatusIcon(imageName){
			var statusPic = $go(go.Picture,
							{source: imageName,
							 background: TREE_CONST.statusPanelStokeColor,
							 margin: TREE_CONST.statusIconMargin,

// todo - is there a hover for status?
//							 ,
//							 mouseEnter: function(e, obj) 
//							 {_warningiconShowHide(obj, true);},
//							 mouseLeave: function(e, obj)
//							 {_warningiconShowHide(obj, false);}
							},
							 new go.Binding("visible", "", function (data)
																 {var picVisible = 
																		 (imageName == "x_153465_discovert.Warning16.svg" && data.status=="Warning") ||
																		 (imageName == "x_153465_discovert.Error16.svg" && data.status=="Critical")
																	return	picVisible;
																 })
						 );
			return statusPic;
