		function _createStatusShape(shape){
			var statusShape = $go(go.Shape, shape,
									{height:TREE_CONST.statusPanelHeight,
									 width:TREE_CONST.statusPanelWidth,
									 strokeWidth:TREE_CONST.statusPanelStrokeWidth,
									 stroke:TREE_CONST.statusPanelStokeColor
									},
									new go.Binding("visible", "", function (data)
																 {var shapeVisible = 
																		 (shape == "Triangle" && data.status=="Warning") ||
																		 (shape == "Circle" && data.status=="Critical")
																	return	shapeVisible;
																 })
								 );
			return statusShape;
		}

		function _createStatusPanel(){
			var statusPanel = 
					$go(go.Panel, "Spot", // panel to hold the image clipped into a circle
							{name: "statusPanel",
							 scale:1,
							 isClipping:true,
							 alignment: new go.Spot(0, 1, TREE_CONST.statusPanelXoffset, TREE_CONST.statusPanelYoffset)
							},
							new go.Binding("visible", "", function (data){
									var statusVisible = data.status=="Critical" ||
											data.status=="Warning";
									return statusVisible;
									}),
							_createStatusShape("Triangle"),
							_createStatusShape("Circle"),
							_createStatusIcon("x_153465_discovert.Error16.svg"),
							_createStatusIcon("x_153465_discovert.Warning16.svg")
						 );
			return statusPanel;
		}

		function _createWarningIcon(){
			var warningIcon = 
					$go(go.Picture,
							{source: "x_153465_discovert.NodeWarning24.svg",
							 margin: TREE_CONST.warningIconMargin,
							 background: TREE_CONST.warningPanelStokeColor,
							 mouseEnter: function(e, obj) 
							 {_warningiconShowHide(obj, true);},
							 mouseLeave: function(e, obj)
							 {_warningiconShowHide(obj, false);}
							}
						 ); // end panel holding circle and unlock icon
			return warningIcon;
		}

		function _createWarningPanel(){
			var warningPanel = 
					$go(go.Panel, "Spot", // panel to hold the image clipped into a circle
							{name: "warningPanel",
							 scale:1,
							 isClipping:true,
							 alignment: new go.Spot(1, 0, TREE_CONST.warningPanelXoffset, TREE_CONST.warningPanelYoffset)
							},		
							new go.Binding("visible", "", function (nodeData){
  								var durationExclamation = nodeData.warning.noSuspenseDate || !nodeData.warning.isSuspenseDateAfterChildren ||
											nodeData.warning.isSuspenseDateAfterParent || nodeData.warning.waitStatewithNoSubtasks ||
											nodeData.warning.waitStateOrderBy || nodeData.warning.isTopSuspenseDateAfterExternalInboundDate ||
											nodeData.warning.isTopSuspenseDateBeforeExternalOutboundDate;
									var assignmentExclamation = nodeData.warning.primaryAssigneeEmpty || nodeData.warning.assignedMemberEmpty || _isAnyUserOOOforTask(nodeData);
									return durationExclamation || assignmentExclamation;
									}),
							new go.Binding("fill", "isSelected", function(s) 
														 {if (s)
															 return TREE_CONST.selectedOutlineBorderColor;
															else
																return "#FFFFFF";
														 }).ofObject(""),
							$go(go.Shape,"Triangle",
									{height:TREE_CONST.warningPanelHeight,
									 width:TREE_CONST.warningPanelWidth,
									 strokeWidth:TREE_CONST.warningPanelStrokeWidth,
									 stroke:TREE_CONST.warningPanelStokeColor}),
							_createWarningIcon()
							)
			return warningPanel;
		}

		function createProfilePicCircle(picNum){
			// TODO - move offset to constants
			var picOffset = picNum * TREE_CONST.profilePicOffset;
			// STRY0111888 - added outer circle for border
			var profilePicCricle =
					$go(go.Shape, "Circle", 
							{width: TREE_CONST.profilePicCircleSize, height: TREE_CONST.profilePicCircleSize, strokeWidth: TREE_CONST.outlineWidth,
							 alignment: new go.Spot(0, 0, TREE_CONST.leftPicCornerOffset + picOffset, TREE_CONST.topPicCornerOffset),
							 fill:TREE_CONST.profilePicFill,
							 stroke:TREE_CONST.profilePicBorder
							},
							{mouseEnter: function(e, obj) 
							 {_membersShowHide(obj, true);},
							 mouseLeave: function(e, obj)
							 {_membersShowHide(obj, false);}
							}
						 );
			return profilePicCricle;
		}

	function createProfilePicPhoto(fieldName, picNum){
		// TODO - move offset to constants
		var picOffset = picNum * TREE_CONST.profilePicOffset;

		//STRY0111888 - changed alignment and works with Spot panel above
		var profilePicPhoto = 
				$go(go.Panel, "Spot", // panel to hold the image clipped into a circle
						{isClipping: true,	
						 alignment: new go.Spot(0, 0, TREE_CONST.leftPicCornerOffset + picOffset, TREE_CONST.topPicCornerOffset)//,
						}, 
						// STRY0113936
						$go(go.Shape, "Circle", 
								{width: TREE_CONST.profilePicSize, 
								 strokeWidth: TREE_CONST.outlineWidth,
								 fill:TREE_CONST.profilePicFill
								}),
						// this is a special picture just for the user
						$go(go.Picture, 
								{desiredSize: new go.Size(TREE_CONST.profilePicSize, TREE_CONST.profilePicSize),
								 visible: true,
								 imageStretch: go.GraphObject.UniformToFill
								}, 
								new go.Binding("source", "", function(data)
															{var photo = "";
															 var profile = data[fieldName + "_profile"];
															 if(profile && profile != "" && profile!=null && profile!=undefined){
																 var lphoto = profile.photo;
																 if(lphoto && lphoto != "" && lphoto!=null && lphoto!=undefined){
																	 photo = lphoto;
																 }
															 }
															 return photo;
															}), 
								new go.Binding("name",fieldName + "_photoName"),
								new go.Binding("visible", "", function(data)
															 {var visible = false;
																var profile = data[fieldName + "_profile"];
																if(profile && profile != "" && profile!=null && profile!=undefined){
																	var photo = profile.photo;
																	if(photo && photo != "" && photo!=null && photo!=undefined){
																		visible = true;
																	} else {
																		visible = false;
																	}
																}
																return visible;
															 })
							 ), // end image picture object							 

						// added initials when photo doesn't exist.
						// add textbox first and always show, then hide image unless image exists
						$go(go.TextBlock, 
								{font: TREE_CONST.fontStyleProfileInitials, 
								 stroke: TREE_CONST.profilePicTextStroke,
								 visible:false
								},
								new go.Binding("text", "", function(data)
															 {var initials="?";
																var profile = data[fieldName + "_profile"];
																if(profile && profile.initials != undefined &&
																	profile.initials !=""){
																	initials = profile.initials;
																}
																return initials;
															 }),
								new go.Binding("visible", "", function(data)
															 {var visible = true;
																var profile = data[fieldName + "_profile"];
																if(profile && profile != "" && profile!=null && profile!=undefined){
																	var photo = profile.photo;
																	if(photo && photo != "" && photo!=null && photo!=undefined){
																		visible = false;
																	} else {
																		visible = true;
																	}
																}
																return visible;
															 })
							 )
					 ); // end panel holding circle and picture
		return profilePicPhoto;
	}

    // common styling for each indicator
    function makeIndicator(propName, label) { // the data property name
        return $go(go.Shape,
            "Circle", {
                width: 12,
                height: 12,
                fill: "white",
                strokeWidth: 0,
                margin: 5
            },
            new go.Binding("fill", propName, function(t) {
                switch (t) {
                    case ("Projected on time"):
                        return TREE_CONST.node_status_ontime;
                    case ("Warning"):
                        return TREE_CONST.node_status_warning;
                    case ("Critical"):
                        return TREE_CONST.node_status_critical;
                    default:
                        return "Gray";
                }
            })
        );
    }

