																	 {var newAlignment;
																		if(treeOrientation == "Horizontal"){
																			newAlignment = new go.Spot(1,0.5, TREE_CONST.rightTreeExpanderOffset, 0);
																		} else if(treeOrientation == "Vertical"){
																			newAlignment = new go.Spot(0.5,1, 0, TREE_CONST.bottomTreeExpanderOffset);
																		}
																		return newAlignment;
																	 })
									 )
							 );
			return nodeTemplate;


    }


    // **************************************************************************************************************	
    // DRAW TREE AND TREE LAYOUT FUCNTIONS
    // This block contains the functions that define the tree structure and capabilities
    // END BLOCK
    // **************************************************************************************************************	

		// STRY0131003 - if user has a conflict for this task, show the OOO schedule conflict indicator
		function _addOutOfOffice(visibleFlag, rowNum, columnNum, margin, task_id, user_id){
			var oooImage;
			var isUserOOO = _isUserOOOforTask(task_id, user_id);

			// user conflict was return the ooo image
			if(isUserOOO){
				oooImage = 
					$go(go.Picture, 
							{visible: visibleFlag,
							 row: rowNum,
							 column: columnNum,
							 margin: margin,
							 background: TREE_CONST.toolTipBackgroundColor,
							 source: 'OOO16.svg'
							});			
			// user conflict was not found return blank text
			} else {
					oooImage =
							$go(go.TextBlock, {

											row: rowNum,
											column: columnNum,
											margin: margin,
											background: TREE_CONST.toolTipBackgroundColor
									},
									""
							);
			}

			return oooImage;		
		}

		// STRY0131003 - function to the OOO array to see if a user on a task is out of the office
		function _isUserOOOforTask(task_id, user_id){
			var isUserOOO = false;
			c.data.task_tree_ooo.filter(function(task){
				if(task.task_id == task_id){
					var userOOO = task.users.filter(function(user){
						if(user.user_id == user_id){
							isUserOOO = true;
						}
					});
				}
			});
			return isUserOOO;
		}

		// STRY0131003 - function to check the ooo object for any user on the task being out of the office
		function _isAnyUserOOOforTask(nodeData){
			// look at users one at a time and return true on first true found else return false
			var isAssignedUserOOO = false;
			var isReviewerOOO= false;
			var isOwnerOOO= false;
			isAssignedUserOOO = _isUserOOOforTask(nodeData.sys_id,nodeData.assigned_to);
			if(!isAssignedUserOOO){
				isReviewerOOO = _isUserOOOforTask(nodeData.sys_id,nodeData.u_reviewer);
			}
			if(!isAssignedUserOOO && !isReviewerOOO){
				isOwnerOOO = _isUserOOOforTask(nodeData.sys_id,nodeData.u_task_requester);
			}
			return isAssignedUserOOO || isReviewerOOO || isOwnerOOO;
		}

    // -----------------------------------------------------------------------------------------------------------------
    // END TOOLTIPS
    // -----------------------------------------------------------------------------------------------------------------

};

