//                                      Changes Client controller.
//
// 2.8.1 | 2023-01-09 | raj  | STRY0131001 - Task Tree- Assignment Tooltip Shows Task Owner and Reviewer
//                                      Added to the tooltip in client script tool tip table
// 2.8.1 | 2023-01-09 | raj  | STRY0131003 - Task Tree- OOO Visual Indicators
//                                      Added to lookup to the tooltip
// 2.8.3HF | 2023-09-21 | raj  | DFCT0012129 - All Wait State Tasks display "Waiting on Creating Subtasks" even if it is in wait state due to "Order by"
//																			Changes made in Client Controller
// 2.8.3HF | 2023-09-24 | raj  | DFCT0012174 - DIA - DHS - Create new task shows incomplete task tree with message "Active Tasks cannot exist under Draft Task. Navigate to the Earliest Task-Order Draft to publish"
//										Changes in Client Controller and HTML
//
//------------------------------------------------------------------------------------------------------------------------

(function() {
		var api_ui_component_data = new api_tasker_ui_component_data();
		var CONST_USER_PREFERENCE_TASK_TREE_PINNED_NAME = 'dtech_task_tree_state_legend_pinned';

    main();

    function main() {
        var taskWidgetIconsAndMessage = new TaskerWidgetIconsAndMessages('discovertasker-recursivetasktreegraph');
        data.settings = taskWidgetIconsAndMessage.loadDefaultsAndSettings($sp);
        data.messages = taskWidgetIconsAndMessage.loadMessages();
        data.icons = taskWidgetIconsAndMessage.loadIcons();

        // DFCT0010684
        data.currentUser = gs.getUserID();
        // DFCT0010652
        data.hide_accordion = (input || {}).hide_accordion || (options || {}).hide_accordion || false;
        // 2.7.0 | 2021-08-27 | mmcc | STRY0107400 - Draft Scheduled Tasks – UI – Publish from Subtasks
        data.isTopTaskOrNotDraft = true;
        data.loadData = false;
        // DFCT0010674
        data.selectedId = (input || {}).sys_id || $sp.getParameter('sys_id');
        data.table = (input || {}).table || $sp.getParameter('table');

        // 2.8 | 2022-08-19 | mmcc | DFCT0011084 - Page Tree Bi-Fold needs to match the standard layout for flexing header-body-footer; add bifold
        data.bifold = (input || {}).bifold || (options || {}).bifold || false;

        // 2.8 | 2022-08-19 | mmcc | DFCT0011084 - Page Tree Bi-Fold needs to match the standard layout for flexing header-body-footer; add bifold
        // DFCT0010674 - STRY0119599
        convertToBool(['bifold', 'hide_accordion']);

        data.dynamic_tree = $sp.getParameter("dynamic_tree"); // KT - TLV - STRY0057360 - Macro Widget
        if ((data.table != "x_153465_discovert_route_task_instance") || (!data.selectedId)) {
            data.topParentTask_id = null;
            return;
        }
        if (input) {
					if(input.getActions==true){
						getActions(input.taskSysId);
						return;
					}

					if(input.setPreference==true){
						_setUserPreferences(input.preferences);
						return;
					}
					data.loadData = input.loadData;

        }

				data.preferences = _getUserPreferences();
        // DFCT0010674 - STRY0119599
        if (data.hide_accordion) {
            data.loadData = true;
        }

        if (data.loadData) {
            _loadTaskTree();
            // STRY0121780 - moved here load toolbar after loading task tree
            _loadToolBars();

        }

    }

		function getActions(taskSysId){
			data.actions = api_ui_component_data.getContextMenuInformation(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME, taskSysId);
			data.actions.objectType = "task";
		}

    function _loadToolBars() {
        // TREE HEADER TOOLBAR
        // STRY0117600 - move toolbar into separate widget to use same functionality across all
        // STRY0120908 - added show separator
        var header_widget_parameters = {
            baseWidget: 'discovertasker-recursivetasktreegraph',
            // STRY0121780
            topId: data.topParentTask_id,
            showSeparator: !data.hide_accordion,
            iconGroup: 'header'
        };
        data.widgetTreeHeaderToolbars = [];
        data.widgetTreeHeaderToolbars.push($sp.getWidget('tasker-tree-toolbar-icons', header_widget_parameters));

        // TREE FOOTER TOOLBAR
        // STRY0117600 - move toolbar into separate widget to use same functionality across all
        var footer_widget_parameters = {
            baseWidget: 'discovertasker-recursivetasktreegraph',
            // STRY0121780
            topId: data.topParentTask_id,
            iconGroup: 'footer'
        };
        data.widgetTreeFooterToolbars = [];
        data.widgetTreeFooterToolbars.push($sp.getWidget('tasker-tree-toolbar-icons', footer_widget_parameters));
    }

    function _loadTaskTree() {

        var grTask = new GlideRecordSecure('x_153465_discovert_route_task_instance');
        if (!grTask.get(data.selectedId)) {
            data.topParentTask_id = null;
            return;
        }
        var id = grTask.getValue("u_top_task");

        var grTopTask = new GlideRecordSecure('x_153465_discovert_route_task_instance');
        if (!grTopTask.get(id)) {
            data.topParentTask_id = null;
            return;
        }
        // DFCT0011096 - replaced data.id with data.topParentTask_id everywhere
        data.topParentTask_id = grTopTask.getValue('sys_id');

        data.task_tree = grTopTask.getValue('u_task_tree');
				// STRY0131003 - Task Tree- OOO Visual Indicators - load the OOO list for tasks in the tree
				data.task_tree_ooo = new Out_of_Office().getTaskTreeOOOSchedules(data.task_tree);

        // STRY0091251 - NOTE: this uses the same data building functions as the 'Tasker List Task Tree' widget id: discovertasker-recursivetasktreelist
        if (data.loadData) {
            // DFCT0010674
            var map = data.map = [];
            var taskWidgetData = new TaskWidgetData();
            data.fieldsInModel = taskWidgetData.loadTaskTreeFieldsInModelAndFieldLabels(grTopTask);
            taskWidgetData.buildTaskMap('discovertasker-recursivetasktreegraph', map, grTopTask, data.fieldsInModel);
        }
    }

		function _getUserPreferences(){
			var preferences = {};
			preferences[CONST_USER_PREFERENCE_TASK_TREE_PINNED_NAME] = {};
			var pinnedPreference = gs.getUser().getPreference(CONST_USER_PREFERENCE_TASK_TREE_PINNED_NAME);
			pinnedPreference = pinnedPreference!=false && pinnedPreference!='false'; 
			preferences[CONST_USER_PREFERENCE_TASK_TREE_PINNED_NAME].value = pinnedPreference;
			return preferences;
		}

		function _setUserPreferences(preferences){
				gs.getUser().savePreference(CONST_USER_PREFERENCE_TASK_TREE_PINNED_NAME,
																		preferences[CONST_USER_PREFERENCE_TASK_TREE_PINNED_NAME].value);
		}

    function convertToBool(names) {
        names.forEach(function(name) {
            data[name] = data[name] == true || data[name] == 'true';
        });
    }

})();
